class SecurityManager {
    private val keyAlias = "payment_key"
    private val transformation = "AES/GCM/NoPadding"
    private val androidKeyStore = "AndroidKeyStore"
    
    init {
        createKeyIfNeeded()
    }
    
    private fun createKeyIfNeeded() {
        val keyStore = KeyStore.getInstance(androidKeyStore)
        keyStore.load(null)
        
        if (!keyStore.containsAlias(keyAlias)) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                val keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES,
                    androidKeyStore
                )
                
                val keyGenParameterSpec = KeyGenParameterSpec.Builder(
                    keyAlias,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setRandomizedEncryptionRequired(true)
                    .build()
                
                keyGenerator.init(keyGenParameterSpec)
                keyGenerator.generateKey()
            }
        }
    }
    
    private fun getKey(): SecretKey {
        val keyStore = KeyStore.getInstance(androidKeyStore)
        keyStore.load(null)
        return keyStore.getKey(keyAlias, null) as SecretKey
    }
    
    fun encryptString(data: String): String {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.M) {
            return Base64.encodeToString(data.toByteArray(), Base64.DEFAULT)
        }
        
        val cipher = Cipher.getInstance(transformation)
        cipher.init(Cipher.ENCRYPT_MODE, getKey())
        
        val iv = cipher.iv
        val encrypted = cipher.doFinal(data.toByteArray())
        
        val combined = iv + encrypted
        return Base64.encodeToString(combined, Base64.DEFAULT)
    }
    
    fun decryptString(encryptedData: String): String {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.M) {
            return String(Base64.decode(encryptedData, Base64.DEFAULT))
        }
        
        val combined = Base64.decode(encryptedData, Base64.DEFAULT)
        val iv = combined.copyOfRange(0, 12)
        val encrypted = combined.copyOfRange(12, combined.size)
        
        val cipher = Cipher.getInstance(transformation)
        val spec = GCMParameterSpec(128, iv)
        cipher.init(Cipher.DECRYPT_MODE, getKey(), spec)
        
        val decrypted = cipher.doFinal(encrypted)
        return String(decrypted)
    }
    
    fun encryptPurchaseData(purchase: PurchaseData): String {
        val json = """
            {
                "orderId": "${purchase.orderId}",
                "productId": "${purchase.productId}",
                "purchaseToken": "${purchase.purchaseToken}",
                "purchaseTime": ${purchase.purchaseTime}
            }
        """.trimIndent()
        return encryptString(json)
    }
    
    fun encryptWalletTransaction(transaction: WalletTransaction): String {
        val json = """
            {
                "id": "${transaction.id}",
                "amount": ${transaction.amount},
                "type": "${transaction.type}",
                "timestamp": ${transaction.timestamp},
                "paymentMethod": "${transaction.paymentMethod?.name ?: ""}",
                "destination": "${transaction.destination ?: ""}",
                "merchantId": "${transaction.merchantId ?: ""}"
            }
        """.trimIndent()
        return encryptString(json)
    }
    
    fun decryptWalletTransaction(encryptedData: String): WalletTransaction {
        val json = decryptString(encryptedData)
        val data = parseJson(json)
        
        return WalletTransaction(
            id = data["id"] ?: "",
            amount = data["amount"]?.toDoubleOrNull() ?: 0.0,
            type = TransactionType.valueOf(data["type"] ?: "PAYMENT"),
            timestamp = data["timestamp"]?.toLongOrNull() ?: 0L,
            paymentMethod = data["paymentMethod"]?.let { PaymentMethod.valueOf(it) },
            destination = data["destination"]?.ifEmpty { null },
            merchantId = data["merchantId"]?.ifEmpty { null }
        )
    }
    
    private fun parseJson(json: String): Map<String, String> {
        val map = mutableMapOf<String, String>()
        val cleanJson = json.replace("{", "").replace("}", "").trim()
        
        cleanJson.split(",").forEach { pair ->
            val parts = pair.split(":")
            if (parts.size == 2) {
                val key = parts[0].trim().replace("\"", "")
                val value = parts[1].trim().replace("\"", "")
                map[key] = value
            }
        }
        
        return map
    }
}

data class PurchaseData(
    val orderId: String,
    val productId: String,
    val purchaseToken: String,
    val purchaseTime: Long
)

data class WalletTransaction(
    val id: String,
    val amount: Double,
    val type: TransactionType,
    val timestamp: Long,
    val paymentMethod: PaymentMethod? = null,
    val destination: String? = null,
    val merchantId: String? = null
)

enum class TransactionType {
    DEPOSIT,
    WITHDRAWAL,
    PAYMENT
}

enum class PaymentMethod {
    CREDIT_CARD,
    DEBIT_CARD,
    BANK_TRANSFER,
    CRYPTO
}

sealed class PurchaseState {
    object Idle : PurchaseState()
    object Ready : PurchaseState()
    object Pending : PurchaseState()
    object Acknowledged : PurchaseState()
    object Cancelled : PurchaseState()
    object Disconnected : PurchaseState()
    data class Success(val purchaseData: PurchaseData) : PurchaseState()
    data class Error(val message: String) : PurchaseState()
}

