class PaymentActivity : Activity() {
    private lateinit var paymentModule: PaymentModule
    
    override fun onCreate(savedInstanceState: android.os.Bundle?) {
        super.onCreate(savedInstanceState)
        
        paymentModule = PaymentModule(applicationContext)
        paymentModule.initialize()
        
        observePaymentStates()
    }
    
    private fun observePaymentStates() {
        CoroutineScope(Dispatchers.Main).launch {
            paymentModule.purchaseState.collect { state ->
                when (state) {
                    is PurchaseState.Success -> handlePurchaseSuccess(state.purchaseData)
                    is PurchaseState.Error -> handlePurchaseError(state.message)
                    else -> {}
                }
            }
        }
    }
    
    private fun handlePurchaseSuccess(purchaseData: PurchaseData) {
        // Handle successful purchase
    }
    
    private fun handlePurchaseError(message: String) {
        // Handle purchase error
    }
    
    fun purchaseProduct(productId: String) {
        paymentModule.launchPurchaseFlow(this, productId)
    }
    
    fun addFunds(amount: Double) {
        paymentModule.addFundsToWallet(amount, PaymentMethod.CREDIT_CARD)
    }
    
    fun makePayment(amount: Double, merchantId: String) {
        paymentModule.processWalletPayment(amount, merchantId)
    }
    
    override fun onDestroy() {
        super.onDestroy()
        paymentModule.release()
    }
